50	static void print_help()
51	{
52	  print_version();
53	  fmt::print(R"(
54	Usage: sim_cpu_name [elf_file] [options]
55	
56	AndesCycle CPU simulator for RISC-V processors
57	
58	Argument:
59	  <elf_file>                  RISC-V ELF binary to simulate
60	
61	General:
62	  --help, -h                  Print this help message and exit
63	  --version                   Display version information and exit
64	  --print-config              Show CPU configuration and exit
65	  --print-memmap              Show memory map layout and exit
66	  --log-level <level>         Set logging verbosity [default: 2]
67	                              (0=trace 1=debug 2=info 3=warn 4=error 5=critical 6=off)
68	
69	Simulation:
70	  --mem-latency  <cycles>     Memory access latency in cycles [default: 1]
71	  --reset-vector <spec>       Set per-hart reset vector
72	                              <addr>        set all harts to <addr>
73	                              <hart>:<addr> set specific hart to <addr>
74	                              Overrides ELF entrypoint if specified
75	
76	Tracing:
77	  --pc-trace  <file>          Enable PC trace logging to CSV file
78	  --kanata    <file>          Enable Kanata pipeline visualization logging
79	  --clarity   <file>          Enable Clarity pipeline visualization logging
80	  --objdump   <file>          Load objdump disassembly for pipeline viewer labels
81	  --kanata-loop-start <pc>    Start PC of the loop body (hex with 0x ok)
82	  --kanata-loop-end   <pc>    End PC of the loop body. Each retire of this PC
83	                              counts as one iteration; combine with --kanata or
84	                              --clarity to dump a steady-state window
85	  --kanata-loop-skip  <N>     Skip first N iterations [default: 0]
86	  --kanata-loop-record <X>    Record next X iterations then exit [default: 1]
87	
88	Debug:
89	  --jtag-port <port>          JTAG remote bitbang port for OpenOCD [default: 9104]
90	
91	Extra Options (require additional license):
92	  --ilm       <image>         Load ILM ROM image
93	  --dlm       <image>         Load DLM ROM image
94	  --waveform  <file>          Enable VCD/FST waveform tracing
95	  --save                      Save context when CPU enters WFI
96	  --continue                  Restore context and resume execution
97	  --context-dir <dir>         Context directory [default: ./saved_ctx]
98	
99	Hybrid (QEMU + Verilator):
100	  --shared-mem-path <file>    mmap-backed file used as main RAM (zero-copy
101	                              shared with QEMU). Requires --shared-mem-size.
102	  --shared-mem-size <bytes>   Size of the shared mmap region; must cover the
103	                              full main memory range
104	  --resume-from-qemu <file>   Resume from a QEMU-side state snapshot. Loads
105	                              architectural state via the in-process Debug
106	                              Module. Mutually exclusive with --continue.
107	)");
108	  // --ilm/--dlm: CPU-specific, not all CPUs have ILM/DLM
109	  // --waveform: requires compile flag VSIMDEBUG
110	  // --save/--continue/--context-dir: requires compile flag VSIMSAVABLE
111	}
