113	extern "C" auto sc_main(const int argc, char* argv[]) -> int
114	try {
115	  spdlog::set_default_logger(spdlog::stderr_color_mt("stderr_logger"));
116	  spdlog::set_pattern("[%^%l%$] %v");
117	
118	  const auto args = [&] {
119	    struct args
120	    {
121	      std::string pc_trace_file{};
122	      std::string elf_file{};
123	      std::optional<uint16_t> jtag_port = std::nullopt;
124	      bool memmap = false;
125	      std::string waveform_file{};
126	      unsigned mem_latency = 1;
127	      std::string ilm_file{};
128	      std::string dlm_file{};
129	      std::string kanata_file{};
130	      std::string objdump_file{};
131	      std::string clarity_file{};
132	      std::optional<uint64_t> kanata_loop_start{};
133	      std::optional<uint64_t> kanata_loop_end{};
134	      uint64_t kanata_loop_skip = 0;
135	      uint64_t kanata_loop_record = 1;
136	      std::vector<std::string> reset_vectors{};
137	      bool continue_ctx = false;
138	      bool save_ctx = false;
139	      std::string context_dir = "./saved_ctx/";
140	      std::string shared_mem_path{};
141	      uint64_t shared_mem_size = 0;
142	      std::string resume_from_qemu{};
143	    } args;
144	
145	    const auto help_and_exit = [] {
146	      print_help();
147	      exit(0);
148	    };
149	
150	    auto p = parser{};
151	    p.shortflag('h', help_and_exit);
152	    p.longflag("help", help_and_exit);
153	    p.longflag("version", [] {
154	      print_version();
155	      exit(0);
156	    });
157	    p.longflag("print-memmap", [&] { args.memmap = true; });
158	    p.longflag("print-config", [] {
159	      print_cpu_configuration();
160	      exit(0);
161	    });
162	    p.longopt("jtag-port", [&](const std::string_view s) {
163	      if (auto n = to_int<uint16_t>(s); n)
164	        args.jtag_port = *n;
165	      else
166	        throw std::runtime_error("invalid number for --jtag-port: "
167	                                 + std::string{s});
168	    });
169	    p.longopt("mem-latency", [&](const std::string_view s) {
170	      if (auto n = to_int<unsigned>(s); n)
171	        args.mem_latency = *n;
172	      else
173	        throw std::runtime_error("invalid number for --mem-latency: "
174	                                 + std::string{s});
175	    });
176	    p.longopt("log-level", [](const std::string_view s) {
177	      if (auto n = to_int<uint16_t>(s); n) {
178	        *n = std::min(*n, (uint16_t) SPDLOG_LEVEL_OFF);
179	        spdlog::set_level(static_cast<spdlog::level::level_enum>(*n));
180	      } else {
181	        throw std::runtime_error("invalid number for --log-level: "
182	                                 + std::string{s});
183	      }
184	    });
185	    p.longopt("waveform",
186	              [&](const std::string_view s) { args.waveform_file = s; });
187	    p.longopt("ilm", [&](const std::string_view s) { args.ilm_file = s; });
188	    p.longopt("dlm", [&](const std::string_view s) { args.dlm_file = s; });
189	    p.longopt("pc-trace",
190	              [&](const std::string_view s) { args.pc_trace_file = s; });
191	    p.longopt("kanata",
192	              [&](const std::string_view s) { args.kanata_file = s; });
193	    p.longopt("objdump",
194	              [&](const std::string_view s) { args.objdump_file = s; });
195	    p.longopt("clarity",
196	              [&](const std::string_view s) { args.clarity_file = s; });
197	    p.longopt("kanata-loop-start", [&](const std::string_view s) {
198	      try {
199	        args.kanata_loop_start = std::stoull(std::string{s}, nullptr, 0);
200	      } catch (...) {
201	        throw std::runtime_error("invalid --kanata-loop-start: "
202	                                 + std::string{s});
203	      }
204	    });
205	    p.longopt("kanata-loop-end", [&](const std::string_view s) {
206	      try {
207	        args.kanata_loop_end = std::stoull(std::string{s}, nullptr, 0);
208	      } catch (...) {
209	        throw std::runtime_error("invalid --kanata-loop-end: "
210	                                 + std::string{s});
211	      }
212	    });
213	    p.longopt("kanata-loop-skip", [&](const std::string_view s) {
214	      try {
215	        args.kanata_loop_skip = std::stoull(std::string{s}, nullptr, 0);
216	      } catch (...) {
217	        throw std::runtime_error("invalid --kanata-loop-skip: "
218	                                 + std::string{s});
219	      }
220	    });
221	    p.longopt("kanata-loop-record", [&](const std::string_view s) {
222	      try {
223	        args.kanata_loop_record = std::stoull(std::string{s}, nullptr, 0);
224	      } catch (...) {
225	        throw std::runtime_error("invalid --kanata-loop-record: "
226	                                 + std::string{s});
227	      }
228	    });
229	    p.longflag("continue", [&] { args.continue_ctx = true; });
230	    p.longflag("save", [&] { args.save_ctx = true; });
231	    p.longopt("context-dir",
232	              [&](const std::string_view s) { args.context_dir = s; });
233	    p.longopt("shared-mem-path",
234	              [&](const std::string_view s) { args.shared_mem_path = s; });
235	    p.longopt("shared-mem-size", [&](const std::string_view s) {
236	      try {
237	        args.shared_mem_size = std::stoull(std::string{s}, nullptr, 0);
238	      } catch (...) {
239	        throw std::runtime_error("invalid --shared-mem-size: "
240	                                 + std::string{s});
241	      }
242	    });
243	    p.longopt("resume-from-qemu", [&](const std::string_view s) {
244	      args.resume_from_qemu = s;
245	    });
246	    p.longopt("reset-vector", [&](const std::string_view s) {
247	      args.reset_vectors.emplace_back(s);
248	    });
249	    p.posarg([&](const std::string_view s) { args.elf_file = s; });
250	    p.parse(std::vector<std::string_view>(argv, argv + argc));
251	    return args;
252	  }();
253	
254	#ifndef VSIMSAVABLE
255	  if (args.save_ctx || args.continue_ctx || args.context_dir != "./saved_ctx/")
256	  {
257	    spdlog::critical(
258	      "--save, --continue, and --context-dir require VSIMSAVABLE build");
259	    std::exit(EXIT_FAILURE);
260	  }
261	#endif
262	
263	  if (!args.resume_from_qemu.empty() && args.continue_ctx)
264	    throw std::runtime_error(
265	      "--resume-from-qemu and --continue are mutually exclusive");
266	
267	  // Pre-flight: validate the state file before any simulation work begins.
268	  if (!args.resume_from_qemu.empty())
269	    (void) hybrid::load_state(args.resume_from_qemu);
270	
271	  print_version();
272	
273	  // systemc and cci init
274	  auto broker = cci_utils::broker{"global_broker"};
275	  cci::cci_register_broker(broker);
276	
277	  const auto time_resolution = sc_core::sc_get_time_resolution();
278	  spdlog::debug("Using time resolution: {}", time_resolution.to_string());
279	
280	  std::optional<MmapBacking> shared_ram;
281	  if (!args.shared_mem_path.empty()) {
282	    if (args.shared_mem_size == 0)
283	      throw std::runtime_error(
284	        "--shared-mem-path requires --shared-mem-size > 0");
285	    shared_ram.emplace(args.shared_mem_path, args.shared_mem_size);
286	  } else if (args.shared_mem_size != 0) {
287	    throw std::runtime_error(
288	      "--shared-mem-size requires --shared-mem-path");
289	  }
290	
291	  // run simulation
292	  const auto do_sim = [&]<typename CPU>() -> int {
293	    Simulator<CPU> sim{
294	      "sim", shared_ram ? shared_ram->span() : std::span<uint8_t>{}};
295	
296	    if (args.memmap) {
297	      sim.platform.interconnect.dump_region();
298	      return 0;
299	    }
300	
301	    sim.set_mem_latency(args.mem_latency);
302	
303	    if (!args.ilm_file.empty())
304	      sim.load_image(args.ilm_file, MEM_TYPE::ILM);
305	
306	    if (!args.dlm_file.empty())
307	      sim.load_image(args.dlm_file, MEM_TYPE::DLM);
308	
309	    // End of elaboration
310	    sc_core::sc_start(sc_core::SC_ZERO_TIME);
311	
312	    const auto t0 = std::chrono::steady_clock::now();
313	
314	    if (!args.waveform_file.empty())
315	      sim.enable_waveform(args.waveform_file);
316	
317	    if (!args.pc_trace_file.empty())
318	      sim.enable_pc_trace(args.pc_trace_file);
319	
320	    if (!args.kanata_file.empty() && !args.clarity_file.empty())
321	      throw std::runtime_error("--kanata and --clarity are mutually exclusive");
322	
323	    std::optional<kanata::LoopGate> loop_gate;
324	    if (args.kanata_loop_start.has_value()
325	        != args.kanata_loop_end.has_value())
326	      throw std::runtime_error(
327	        "--kanata-loop-start and --kanata-loop-end must be specified together");
328	    if (args.kanata_loop_start.has_value()) {
329	      if (args.kanata_file.empty() && args.clarity_file.empty())
330	        throw std::runtime_error(
331	          "--kanata-loop-* requires --kanata or --clarity");
332	      if (args.kanata_loop_record == 0)
333	        throw std::runtime_error("--kanata-loop-record must be >= 1");
334	      loop_gate = kanata::LoopGate{*args.kanata_loop_start,
335	                                   *args.kanata_loop_end,
336	                                   args.kanata_loop_skip,
337	                                   args.kanata_loop_record};
338	    }
339	
340	    if (!args.kanata_file.empty())
341	      sim.enable_kanata(args.kanata_file, args.objdump_file, loop_gate);
342	
343	    if (!args.clarity_file.empty())
344	      sim.enable_clarity(args.clarity_file, args.objdump_file, loop_gate);
345	
346	    if (!args.elf_file.empty() && !args.continue_ctx)
347	      sim.load_elf(args.elf_file);
348	
349	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
350	    for (const auto& s: args.reset_vectors) {
351	      auto [hart, addr] = parse_reset_vector(s);
352	      if (hart) {
353	        sim.set_reset_vector(*hart, addr);
354	      } else {
355	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
356	          sim.set_reset_vector(i, addr);
357	      }
358	    }
359	
360	    if (args.continue_ctx)
361	      spdlog::info("You're resuming program from the given context");
362	
363	    if (args.jtag_port)
364	      sim.init_debug_port(args.jtag_port.value());
365	
366	    if (!args.resume_from_qemu.empty())
367	      sim.enable_resume_from_qemu(args.resume_from_qemu);
368	
369	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx
370	        && args.resume_from_qemu.empty())
371	      throw std::runtime_error(
372	        "Required arg : program, --jtag-port, or --resume-from-qemu");
373	
374	    if (args.continue_ctx || args.save_ctx) {
375	      std::string_view s = args.context_dir;
376	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
377	        throw std::runtime_error("Error: Path " + std::string{s}
378	                                 + " exists but is not a directory.");
379	      if (!std::filesystem::exists(s)) {
380	        try {
381	          std::filesystem::create_directories(s);
382	        } catch (const std::filesystem::filesystem_error& e) {
383	          throw std::runtime_error(std::string{"Failed to create directory: "}
384	                                   + e.what());
385	        }
386	      }
387	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
388	    }
389	
390	    sim.reset();
391	
392	    sim.apply_resume_from_qemu();
393	
394	    const int exit_code = sim.run();
395	
396	    sim.cpu.final();
397	
398	    const auto t1 = std::chrono::steady_clock::now();
399	    const auto cycles = sim.get_cycles();
400	    spdlog::info("{} cycles simulated", cycles);
401	    if (cycles > 0) {
402	      const auto ms =
403	        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
404	      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
405	                   ms.count() % 1000,
406	                   double(cycles) / double(ms.count()) * 1000.0);
407	    }
408	    return exit_code;
409	  };
410	
411	  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
412	
413	} catch (const std::exception& e) {
414	  spdlog::critical("fatal exception: {}\n", e.what());
415	  std::exit(EXIT_FAILURE);
416	} catch (...) {
417	  std::terminate();
418	}
