1	// QEMU TCG plugin: drains architectural state and exits when the guest
2	// retires `csrwi 0x7C0, 0` (the magic enter-detail trigger).
3	//
4	// The plugin uses the same insn pattern matcher and ABI struct as the vsim
5	// side; both consume hybrid/insn_match.h and hybrid/state_abi.h verbatim.
6	
7	#include "hybrid/insn_match.h"
8	#include "hybrid/state_abi.h"
9	
10	#include <qemu-plugin.h>
11	
12	#include <glib.h>
13	
14	#include <fcntl.h>
15	#include <stddef.h>
16	#include <stdint.h>
17	#include <stdio.h>
18	#include <stdlib.h>
19	#include <string.h>
20	#include <unistd.h>
21	#include <limits.h>
22	
23	QEMU_PLUGIN_EXPORT int qemu_plugin_version = QEMU_PLUGIN_VERSION;
24	
25	typedef struct {
26	    struct qemu_plugin_register *gpr[32];
27	    struct qemu_plugin_register *pc;
28	} VcpuRegs;
29	
30	static struct qemu_plugin_scoreboard *vcpu_state;
31	static char *outfile_path;
32	
33	// GPR ABI names as exposed by QEMU's RISC-V gdbstub; index = x register index.
34	static const char *const gpr_names[32] = {
35	    "zero", "ra",  "sp",  "gp",  "tp",  "t0", "t1", "t2",
36	    "s0",   "s1",  "a0",  "a1",  "a2",  "a3", "a4", "a5",
37	    "a6",   "a7",  "s2",  "s3",  "s4",  "s5", "s6", "s7",
38	    "s8",   "s9",  "s10", "s11", "t3",  "t4", "t5", "t6",
39	};
40	
41	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
42	{
43	    for (guint i = 0; i < regs->len; i++) {
44	        qemu_plugin_reg_descriptor *rd =
45	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
46	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
47	            return rd->handle;
48	        }
49	    }
50	    return NULL;
51	}
52	
53	static void vcpu_init(qemu_plugin_id_t id, unsigned int vcpu_idx)
54	{
55	    (void) id;
56	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
57	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
58	    for (int i = 0; i < 32; i++) {
59	        v->gpr[i] = find_reg(regs, gpr_names[i]);
60	    }
61	    v->pc = find_reg(regs, "pc");
62	}
63	
64	static uint64_t read_reg64(struct qemu_plugin_register *h)
65	{
66	    if (!h) return 0;
67	    g_autoptr(GByteArray) buf = g_byte_array_new();
68	    int sz = qemu_plugin_read_register(h, buf);
69	    if (sz <= 0) return 0;
70	    uint64_t v = 0;
71	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
72	    return v;
73	}
74	
75	// Atomic on POSIX: write to .tmp, fsync, rename.
76	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
77	{
78	    char tmp[PATH_MAX];
79	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
80	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
81	    if (fd < 0) {
82	        perror("hybrid_handoff: open tmp");
83	        return -1;
84	    }
85	    ssize_t want = (ssize_t) sizeof(*s);
86	    ssize_t got = write(fd, s, sizeof(*s));
87	    if (got != want) {
88	        perror("hybrid_handoff: write");
89	        close(fd);
90	        unlink(tmp);
91	        return -1;
92	    }
93	    fsync(fd);
94	    close(fd);
95	    if (rename(tmp, path) != 0) {
96	        perror("hybrid_handoff: rename");
97	        unlink(tmp);
98	        return -1;
99	    }
100	    return 0;
101	}
102	
103	static void on_handoff(unsigned int vcpu_idx, void *udata)
104	{
105	    hybrid_handoff_kind kind = (hybrid_handoff_kind) (uintptr_t) udata;
106	    if (kind != HYBRID_HANDOFF_ENTER) {
107	        // Phase 2 is one-way (QEMU -> vsim) only; ignore exit/runtime.
108	        return;
109	    }
110	
111	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
112	    struct hybrid_state_v1 s = {0};
113	    s.magic   = HYBRID_STATE_MAGIC;
114	    s.version = HYBRID_STATE_VERSION;
115	    s.flags   = HYBRID_FLAG_RV64;
116	    s.hart_id = vcpu_idx;
117	    s.priv    = 3;  // refined when CSR plumbing lands in Phase 5
118	    s.pc      = read_reg64(v->pc);
119	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
120	
121	    if (write_state_atomic(&s, outfile_path) != 0) {
122	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
123	        exit(2);
124	    }
125	    fprintf(stderr,
126	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
127	            outfile_path, s.pc);
128	    exit(0);
129	}
130	
131	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
132	{
133	    (void) id;
134	    size_t n = qemu_plugin_tb_n_insns(tb);
135	    for (size_t i = 0; i < n; i++) {
136	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
137	        size_t sz = qemu_plugin_insn_size(insn);
138	        if (sz != 4) continue;
139	        uint32_t raw = 0;
140	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
141	            continue;
142	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
143	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
144	        qemu_plugin_register_vcpu_insn_exec_cb(
145	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS,
146	            (void *) (uintptr_t) kind);
147	    }
148	}
149	
150	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
151	                                           const qemu_info_t *info,
152	                                           int argc, char **argv)
153	{
154	    (void) info;
155	    for (int i = 0; i < argc; i++) {
156	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
157	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
158	            outfile_path = g_strdup(tok[1]);
159	        } else {
160	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
161	            return -1;
162	        }
163	    }
164	    if (!outfile_path) {
165	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
166	        return -1;
167	    }
168	
169	    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
170	    qemu_plugin_register_vcpu_init_cb(id, vcpu_init);
171	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
172	    return 0;
173	}
